INSERT INTO blog_posts (title, excerpt, content, author, publish_date, status, slug, tags, seo_title, seo_description, image)
VALUES
('Dernières actualités fiscales (impots.cm)', 'Consultez les dernières parutions et mises à jour de la Direction Générale des Impôts du Cameroun.', 'Découvrez les récentes notes d''information, les échéances fiscales et les nouvelles directives publiées sur le portail de la Direction Générale des Impôts du Cameroun. Pour plus de détails, visitez <a href="https://www.impots.cm" target="_blank" rel="noopener noreferrer">impots.cm</a>.', 'PRISMA GESTION', CURRENT_TIMESTAMP, 'published', 'dernieres-actualites-fiscales-impots-cm', ARRAY['Fiscalité', 'Cameroun', 'DGI'], 'Actualités fiscales DGI Cameroun | PRISMA GESTION', 'Les dernières actualités de la Direction Générale des Impôts du Cameroun.', 'https://images.unsplash.com/photo-1554224154-26032ff26273?auto=format&fit=crop&w=800&q=80'),
('Informations de la CNPS (cnps.cm)', 'Les dernières actualités concernant la sécurité sociale au Cameroun avec la CNPS.', 'Restez informé sur les allocations familiales, les pensions de retraite et toutes les informations relatives à la prévoyance sociale publiées par la Caisse Nationale de Prévoyance Sociale. Pour lire la suite, rendez-vous sur <a href="https://www.cnps.cm" target="_blank" rel="noopener noreferrer">cnps.cm</a>.', 'PRISMA GESTION', CURRENT_TIMESTAMP, 'published', 'informations-cnps-cameroun', ARRAY['Social', 'Cameroun', 'CNPS'], 'Actualités CNPS Cameroun | PRISMA GESTION', 'Les dernières actualités de la Caisse Nationale de Prévoyance Sociale du Cameroun.', 'https://images.unsplash.com/photo-1521737604893-d14cc237f11d?auto=format&fit=crop&w=800&q=80'),
('Nouvelles d''E-GECAM', 'Suivez les dernières parutions et informations des entreprises et du patronat.', 'Mettez-vous à jour avec les informations économiques, les rencontres sectorielles et les publications d''E-GECAM, acteur majeur de l''économie camerounaise. Plus de détails sur <a href="https://www.egecam.cm" target="_blank" rel="noopener noreferrer">egecam.cm</a>.', 'PRISMA GESTION', CURRENT_TIMESTAMP, 'published', 'nouvelles-egecam', ARRAY['Économie', 'Cameroun', 'Entreprises'], 'Actualités E-GECAM | PRISMA GESTION', 'Les dernières actualités et publications de E-GECAM.', 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=800&q=80'),
('Actualités de la DGICAM sur Facebook', 'Suivez la communication officielle de la DGICAM sur les réseaux sociaux.', 'Retrouvez les annonces, les événements récents et les publications communautaires de la DGICAM. Visitez la page officielle : <a href="https://web.facebook.com/DGICAM" target="_blank" rel="noopener noreferrer">https://web.facebook.com/DGICAM</a>.', 'PRISMA GESTION', CURRENT_TIMESTAMP, 'published', 'actualites-dgicam-facebook', ARRAY['Actualités', 'DGICAM', 'Réseaux Sociaux'], 'Actualités DGICAM Facebook | PRISMA GESTION', 'Les dernières publications de la DGICAM sur Facebook.', 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=800&q=80');
